VALUES
  ('judicial-57f41407-moex-00523', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲男乙女為夫妻，乙女卻於婚姻關係存續中，與丙男生下一子丁。下列何者無婚生否認權？', '["甲", "乙", "丙", "丁"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00524', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲喪偶，父母雙亡，有乙、丙二子。某日甲、乙口角，乙持刀殺甲未遂，而受刑之宣告。甲先於丙死亡。 丙因未婚無子，死亡時立遺囑，將所有財產遺贈於丁。下列敘述何者正確？', '["乙為丙之遺產繼承人", "丙之遺贈違反特留分部分為無效", "丁得受遺贈丙之所有財產", "乙得對丁行使扣減權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00525', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲父乙子於清明節搭車返鄉掃墓，途中不幸發生重大交通事故，甲乙當場罹難同時死亡。甲尚有妻丙、子 丁。乙則有子戊、己。甲之遺產應由何人繼承？', '["丙、丁", "乙、丙、丁", "丙、丁、戊、己", "丙、乙、戊、己"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00526', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列何者為間接占有人？', '["承租人", "受寄人", "區分地上權人", "出典人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00527', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於物權行為無因性之修正，下列何者為我國實務所採？', '["共同瑕疵理論", "條件關聯性理論", "法律行為一體性理論", "有因理論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00528', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲受僱於乙，負責開車送貨。某日，甲送貨途中，因違規左轉而撞到行人丙，丙有醫療費用等支出。依民 法規定，下列敘述何者錯誤？', '["丙得向甲請求損害賠償", "除乙證明其選任甲及監督甲之職務執行已盡相當之注意，或縱加以相當之注意而仍不免發生損害外，丙 得向乙請求損害賠償", "丙得同時或先後向甲或乙請求賠償其全部損害", "若乙向丙賠償後，乙對甲無求償權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00529', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲於大學校園內擺設裝有自煮咖啡設備之自動販賣機，外面標示各種咖啡之價格。關於甲貨物標定賣價陳 列之行為，下列敘述何者正確？', '["要約引誘", "推定要約", "視為要約", "視為承諾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00530', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '有關刑事訴訟法第95條第1項所定權利告知義務，下列敘述何者錯誤？', '["權利告知，可在訊問被告後為之", "違反權利告知的程序，所取得經拘捕被告的自白，原則上不得作為證據", "權利告知的內容包括犯罪嫌疑以及所犯的所有罪名", "被告選任辯護人後，要求等辯護人到場，此時應停止訊問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00531', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '偵查中羈押審查程序，有關被告辯護人閱卷權，下列敘述何者錯誤？', '["除法律另有規定外，得檢閱卷宗及證物並得抄錄或攝影", "辯護人亦得影印聲請羈押卷證以外之其他相關卷宗", "辯護人不得為追究員警之違法搜索，召開記者會公開持有之偵查中證據資料", "被告無辯護人時，法院應以適當方式使被告獲知卷證內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00532', 'judicial-57f41407', 'judicial-57f41407-moex-112-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列何項刑事訴訟程序中，審判長有為被告指定辯護人之義務？', '["被告犯高等法院管轄第一審案件，於審判中經選任辯護人者", "被告具原住民身分者，於受司法警察調查中，未經選任辯護人者", "偵查中之羈押審查程序未經選任辯護人者", "被告為低收入戶或中低收入戶，於審判中未經選任辯護人，亦未聲請指定者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "53559b9cd29b", "answer_pdf_sha1": "a4ca9f3152ec", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0316", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
